#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_NODES 1000
#define MAX_CHILDREN 2

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* createNode(int val) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->val = val;
    newNode->left = NULL;
    newNode->right = NULL;
    return newNode;
}

// Function to perform BFS and calculate the vertical order traversal
void bfs(Node* root, int** result, int* resultSize, int* resultColumnSizes, int* returnSize) {
    if (root == NULL) return;

    // Initialize the queue with the root node
    Node** queue = (Node**)malloc(MAX_NODES * sizeof(Node*));
    int* columnValues = (int*)malloc(MAX_NODES * sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = root;
    columnValues[rear - 1] = 0;

    // Perform BFS
    while (front < rear) {
        Node* currentNode = queue[front];
        int currentColumn = columnValues[front];
        front++;

        // Add the current node to the result
        if (*resultSize == 0 || currentColumn < 0 || currentColumn >= *resultSize) {
            // If the current column is out of bounds, resize the result array
            int newSize = *resultSize + 1;
            int** temp = (int**)malloc(newSize * sizeof(int*));
            for (int i = 0; i < *resultSize; i++) {
                temp[i] = result[i];
            }
            free(result);
            result = temp;
            *resultSize = newSize;
        }
        if (resultColumnSizes[currentColumn] == 0) {
            result[currentColumn] = (int*)malloc(sizeof(int));
        } else {
            result[currentColumn] = (int*)realloc(result[currentColumn], (resultColumnSizes[currentColumn] + 1) * sizeof(int));
        }
        result[currentColumn][resultColumnSizes[currentColumn]++] = currentNode->val;

        // Add the left and right children to the queue
        if (currentNode->left != NULL) {
            queue[rear] = currentNode->left;
            columnValues[rear] = currentColumn - 1;
            rear++;
        }
        if (currentNode->right != NULL) {
            queue[rear] = currentNode->right;
            columnValues[rear] = currentColumn + 1;
            rear++;
        }
    }

    free(queue);
    free(columnValues);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Node* root = NULL;
        int* values = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &values[i]);
        }
        root = createNode(values[0]);
        Node** nodes = (Node**)malloc(N * sizeof(Node*));
        nodes[0] = root;
        for (int i = 1; i < N; i++) {
            if (values[i] != -1) {
                Node* newNode = createNode(values[i]);
                nodes[i] = newNode;
                if (i % 2 == 1) {
                    nodes[(i - 1) / 2]->left = newNode;
                } else {
                    nodes[(i - 2) / 2]->right = newNode;
                }
            }
        }
        int** result = (int**)malloc(MAX_NODES * sizeof(int*));
        int resultSize = 0;
        int* resultColumnSizes = (int*)malloc(MAX_NODES * sizeof(int));
        for (int i = 0; i < MAX_NODES; i++) {
            resultColumnSizes[i] = 0;
        }
        bfs(root, result, &resultSize, resultColumnSizes, &T);
        printf("[");
        for (int i = 0; i < resultSize; i++) {
            printf("[");
            for (int j = 0; j < resultColumnSizes[i]; j++) {
                printf("%d", result[i][j]);
                if (j < resultColumnSizes[i] - 1) {
                    printf(", ");
                }
            }
            printf("]");
            if (i < resultSize - 1) {
                printf(", ");
            }
        }
        printf("]\n");
        free(result);
        free(resultColumnSizes);
        free(values);
        free(nodes);
    }
    return 0;
}

