#include <iostream>
#include <vector>
#include <queue>
#include <map>
#include <algorithm>
using namespace std;

// Define the structure for a tree node
struct Node {
    int val;
    Node* left;
    Node* right;
    Node(int x) : val(x), left(NULL), right(NULL) {}
};

// Function to perform BFS and calculate the vertical order traversal
vector<vector<int>> verticalTraversal(Node* root) {
    if (root == NULL) return {};

    // Initialize the queue with the root node
    queue<pair<Node*, int>> q;
    q.push({root, 0});
    map<int, vector<pair<int, int>>> m;
    map<int, int> columnCount;

    // Perform BFS
    while (!q.empty()) {
        auto node = q.front().first;
        int column = q.front().second;
        q.pop();

        // Add the current node to the map
        m[column].push_back({node->val, columnCount[column]++});

        // Add the left and right children to the queue
        if (node->left != NULL) {
            q.push({node->left, column - 1});
        }
        if (node->right != NULL) {
            q.push({node->right, column + 1});
        }
    }

    // Sort the nodes in each column based on their row and value
    for (auto& p : m) {
        sort(p.second.begin(), p.second.end(), [](const pair<int, int>& a, const pair<int, int>& b) {
            if (a.second == b.second) return a.first < b.first;
            return a.second < b.second;
        });
    }

    // Create the result vector
    vector<vector<int>> result;
    for (auto& p : m) {
        vector<int> column;
        for (auto& node : p.second) {
            column.push_back(node.first);
        }
        result.push_back(column);
    }

    return result;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        Node* root = NULL;
        vector<int> values(N);
        for (int i = 0; i < N; i++) {
            cin >> values[i];
        }
        root = new Node(values[0]);
        vector<Node*> nodes(N);
        nodes[0] = root;
        for (int i = 1; i < N; i++) {
            if (values[i] != -1) {
                nodes[i] = new Node(values[i]);
                if (i % 2 == 1) {
                    nodes[(i - 1) / 2]->left = nodes[i];
                } else {
                    nodes[(i - 2) / 2]->right = nodes[i];
                }
            }
        }
        vector<vector<int>> result = verticalTraversal(root);
        cout << "["];
        for (int i = 0; i < result.size(); i++) {
            cout << "["];
            for (int j = 0; j < result[i].size(); j++) {
                cout << result[i][j];
                if (j < result[i].size() - 1) {
                    cout << ", ";
                }
            }
            cout << "]";
            if (i < result.size() - 1) {
                cout << ", ";
            }
        }
        cout << "]\n";
        for (int i = 0; i < N; i++) {
            delete nodes[i];
        }
    }
    return 0;
}

