public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] values = new int[N];
            for (int i = 0; i < N; i++) {
                values[i] = sc.nextInt();
            }
            Node root = new Node(values[0]);
            Node[] nodes = new Node[N];
            nodes[0] = root;
            for (int i = 1; i < N; i++) {
                if (values[i] != -1) {
                    nodes[i] = new Node(values[i]);
                    if (i % 2 == 1) {
                        nodes[(i - 1) / 2].left = nodes[i];
                    } else {
                        nodes[(i - 2) / 2].right = nodes[i];
                    }
                }
            }
            List<List<Integer>> result = verticalTraversal(root);
            System.out.print("[");
            for (int i = 0; i < result.size(); i++) {
                System.out.print("[");
                for (int j = 0; j < result.get(i).size(); j++) {
                    System.out.print(result.get(i).get(j));
                    if (j < result.get(i).size() - 1) {
                        System.out.print(", ");
                    }
                }
                System.out.print("]");
                if (i < result.size() - 1) {
                    System.out.print(", ");
                }
            }
            System.out.println("]");
        }
    }

    public static List<List<Integer>> verticalTraversal(Node root) {
        if (root == null) return new ArrayList<>();

        Queue<Pair> queue = new LinkedList<>();
        queue.offer(new Pair(root, 0));
        Map<Integer, List<Pair>> map = new TreeMap<>();

        while (!queue.isEmpty()) {
            Pair pair = queue.poll();
            Node node = pair.node;
            int column = pair.column;

            map.computeIfAbsent(column, k -> new ArrayList<>()).add(pair);

            if (node.left != null) {
                queue.offer(new Pair(node.left, column - 1));
            }
            if (node.right != null) {
                queue.offer(new Pair(node.right, column + 1));
            }
        }

        List<List<Integer>> result = new ArrayList<>();
        for (List<Pair> list : map.values()) {
            List<Integer> column = new ArrayList<>();
            for (Pair pair : list) {
                column.add(pair.node.val);
            }
            result.add(column);
        }
        return result;
    }

    static class Node {
        int val;
        Node left;
        Node right;
        Node(int val) {
            this.val = val;
        }
    }

    static class Pair {
        Node node;
        int column;
        Pair(Node node, int column) {
            this.node = node;
            this.column = column;
        }
    }
}

