    for i in range(1, N):
        if values[i] != -1:
            node = Node(values[i])
            nodes.append(node)
            if i % 2 == 1:
                nodes[(i - 1) // 2].left = node
            else:
                nodes[(i - 2) // 2].right = node
    result = verticalTraversal(root)
    print('[', end='')
